import React from 'react';
import './Home.css';
import tshirt from '../tshirt.webp';
import shirt from '../shirt.webp';
import pant from '../pant.webp';

import Slider from 'react-slick';
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";




const offers = [
  "🔥 Flat 50% off on all T-Shirts!",
  "🚚 Free Delivery for orders above ₹999!",
  "🎉 New Summer Collection Just Arrived!",
  "💳 UPI & Cash On Delivery Available!",
  "🧥 Trending: Oversized Hoodies Back in Stock!"
];

function Home() {
  const bannerImages = [
    "/images/back.jpg",
    "/images/beautiful.jpg",
    "/images/images.jpg"
  ];

  const settings = {
    dots: true,
    infinite: true,
    autoplay: true,
    autoplaySpeed: 2000,
    arrows: false,
    slidesToShow: 1,
    slidesToScroll: 1
  };

  const [index, setIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setIndex((prevIndex) => (prevIndex + 1) % offers.length);
    }, 2000); // 5 seconds

    return () => clearInterval(interval);
  }, []);

  return (
    <div className="home-container">

      {/* 🔁 Hero Banner Section */}
      <div className="hero-banner">
        <Slider {...settings}>
          {bannerImages.map((img, index) => (
            <div key={index}>
              <img src={img} alt={`Banner ${index}`} className="banner-img" />
            </div>
          ))}
        </Slider>
      </div>

      {/* 🛍️ Featured Products */}
      <section className="products-section">
        <h2 className='hd'>🛍️ Featured Products</h2>
        <div className="product-list">
          <div className="product-card">
            <img src={tshirt} alt="T-Shirt" />
            <h3>Cool T-Shirt</h3>
            <p>₹4S99</p>
          </div>
          <div className="product-card">
            <img src={shirt} alt="Dress" />
            <h3>Stylish Dress</h3>
            <p>₹999</p>
          </div>
          <div className="product-card">
            <img src={pant} alt="Jeans" />
            <h3>Classic Jeans</h3>
            <p>₹799</p>
          </div>
        </div>
      </section>

      <div className="offer-banner">
        <p>{offers[index]}</p>
      </div>

      {/* 🔽 New Hero Banner at Bottom */}
      <div className="cta-banner-container">
        <img src="/images/final-banner.jpg" alt="Contact Us Banner" className="cta-banner" />

        <a
          href="https://wa.me/919876543210"  // 🔁 Replace with your number
          target="_blank"
          rel="noopener noreferrer"
          className="cta-whatsapp-btn"
        >
          💬 Chat with us on WhatsApp
        </a>
      </div>

      <footer className="footer">
        <div className="footer-content">
          <div className="footer-logo">🧥 Dora’s Clothing</div>

          <div className="footer-links">
            <a href="/">Home</a>
            <a href="/products">Products</a>
            <a href="/contact">Contact</a>
          </div>

          <div className="footer-contact">
            <p>📞 +91 98765 43210</p>
            <p>✉️ support@dorasclothing.com</p>
          </div>

          <div className="footer-social">
            <a href="https://wa.me/919876543210" target="_blank" rel="noopener noreferrer">WhatsApp</a>
            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer">Instagram</a>
          </div>
        </div>

        <div className="footer-bottom">
          © {new Date().getFullYear()} Dora’s Clothing. All rights reserved.
        </div>
      </footer>

    </div>
  );
}

export default Home;
